sql:
SELECT name
FROM weapons
WHERE weapon_id = 0;

SELECT name
FROM weapons
ORDER BY name ASC;

external_knowledge:
- "most destructive" refers to the highest total damage potential; 
- total damage potential is the sum of physical, magical, fire, lightning, and holy damage; 
- the ranking is based on the descending order of total damage potential.

sql:
SELECT attribute_value
FROM weapon_attributes
WHERE weapon_id = 1;

SELECT name
FROM weapons
WHERE critical_boost > (SELECT AVG(critical_boost) FROM weapons);

SELECT weapon_id
FROM character_equipment
WHERE character_id = 1 AND slot = 'Main Hand';

SELECT
    (SELECT SUM(w.magical_damage)
     FROM characters c
     JOIN character_equipment ce ON c.character_id = ce.character_id
     JOIN weapons w ON ce.weapon_id = w.weapon_id
     WHERE c.character_id = 0
    ) +
    (SELECT SUM(w.magical_damage)
     FROM weapons w
    ) AS total_magic_damage;

SELECT AVG(physical_damage) AS average_physical_damage
FROM weapons
WHERE strength_requirement = '16 D';
